import java.util.List;
import java.util.ArrayList;

class Solution {
    private boolean canReachBottom(int[][] grid, int row, int col) {
        if (row == grid.length - 1) return true;
        grid[row][col] = 1;

        int[] dr = {-1, 0, 1, 0};
        int[] dc = {0, 1, 0, -1};

        for (int i = 0; i < 4; ++i) {
            int nr = row + dr[i], nc = col + dc[i];
            if (nr >= 0 && nc >= 0 && nr < grid.length && nc < grid[0].length && grid[nr][nc] == 0) {
                if (canReachBottom(grid, nr, nc)) return true;
            }
        }
        return false;
    }

    public int latestDayToCross(int row, int col, int[][] cells) {
        int[][] grid = new int[row][col];
        int ans = 0;
        for (int i = 0; i < cells.length; ++i) {
            grid[cells[i][0] - 1][cells[i][1] - 1] = 1;

            boolean found = false;
            for (int j = 0; j < col; ++j) {
                if (grid[0][j] == 0 && canReachBottom(grid, 0, j)) {
                    found = true;
                    break;
                }
            }

            if (!found) {
                ans = i;
                break;
            }
        }
        return ans;
    }
}
